import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingCart, User, MapPin } from 'lucide-react';
import { CartContext } from '../context/CartContext';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const { cartCount } = useContext(CartContext);
  const role = localStorage.getItem('role');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('role');
    navigate('/login');
  };

  return (
    <nav className="bg-white shadow">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-stretch">
            <div className="flex-shrink-0 flex items-center pr-6 border-r border-gray-100">
              <Link to="/" className="text-3xl font-extrabold text-gray-900 tracking-tight">Smart<span className="text-blue-600">Point</span></Link>
            </div>

            <div className="hidden md:flex ml-4 items-center px-4 py-2 rounded-lg hover:bg-gray-50 cursor-pointer group transition-colors">
               <MapPin className="text-blue-600 w-6 h-6 mr-3 group-hover:animate-bounce" />
               <div className="flex flex-col justify-center">
                  <span className="text-[11px] text-gray-500 font-bold uppercase tracking-wider leading-tight">Delivering to Vaibhav</span>
                  <span className="text-sm text-gray-900 font-extrabold leading-none mt-0.5">Bangalore 560001</span>
               </div>
            </div>

            <div className="hidden sm:ml-6 sm:flex sm:space-x-8 items-center pl-6 border-l border-gray-100">
              <Link to="/" className="text-gray-900 hover:text-primary transition-colors hover-underline">Home</Link>
              {token && <Link to="/dashboard" className="text-gray-900 hover:text-primary transition-colors">Dashboard</Link>}
            </div>
          </div>
          <div className="flex items-center space-x-4">
            <Link to="/dashboard" className="relative text-gray-700 hover:text-blue-600 transition group p-1 mr-2" title="My Account">
                <User className="w-7 h-7 transform group-hover:scale-110 transition-transform" />
            </Link>
            <Link to="/checkout" className="relative text-gray-700 hover:text-blue-600 transition group p-1 mr-4">
               <ShoppingCart className="w-7 h-7 transform group-hover:scale-110 transition-transform" />
               {!!cartCount && cartCount > 0 && (
                 <span className="absolute -top-1 -right-2 bg-red-500 text-white text-[10px] font-extrabold rounded-full h-5 w-5 flex items-center justify-center border-2 border-white shadow-sm">
                   {cartCount}
                 </span>
               )}
            </Link>
            {!token ? (
              <>
                <Link to="/login" className="text-gray-900 hover:text-primary">Login</Link>
                <Link to="/register" className="btn-primary">Sign up</Link>
              </>
            ) : (
              <button onClick={handleLogout} className="text-gray-900 hover:text-red-600 transition-colors">
                Logout
              </button>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
